import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { FashionService, Fashion } from '../fashion.service';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-fashion-list',
  standalone: true,
  imports: [CommonModule],
  template: `
    <h2>Fashion List</h2>
    <button (click)="addNew()">Add New Fashion</button>
    <table border="1">
      <thead>
        <tr>
          <th>Title</th>
          <th>Style</th>
          <th>Thumbnail</th>
          <th>Actions</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let fashion of fashions">
          <td>{{ fashion.title }}</td>
          <td>{{ fashion.style }}</td>
          <td><img [src]="fashion.thumbnail" width="50" /></td>
          <td>
            <button (click)="view(fashion._id!)">View</button>
            <button (click)="edit(fashion._id!)">Edit</button>
            <button (click)="delete(fashion._id!)">Delete</button>
          </td>
        </tr>
      </tbody>
    </table>
  `,
  styles: []
})
export class FashionListComponent implements OnInit {
  fashions: Fashion[] = [];

  constructor(private fashionService: FashionService, private router: Router) {}

  ngOnInit() {
    this.loadFashions();
  }

  loadFashions() {
    this.fashionService.getFashions().subscribe(data => this.fashions = data);
  }

  addNew() {
    this.router.navigate(['/fashions/add']);
  }

  view(id: string) {
    this.router.navigate(['/fashions/view', id]);
  }

  edit(id: string) {
    this.router.navigate(['/fashions/edit', id]);
  }

  delete(id: string) {
    if (confirm('Are you sure to delete?')) {
      this.fashionService.deleteFashion(id).subscribe(() => this.loadFashions());
    }
  }
}
